# Definition for singly-linked list.
class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

class Solution:
    def mergeKLists(self, lists: list[ListNode]) -> ListNode:
        if not lists:
            return None
        return self._merge_range(lists, 0, len(lists) - 1)

    def _merge_range(self, lists: list[ListNode], left: int, right: int) -> ListNode:
        if left > right:
            return None
        if left == right:
            return lists[left]

        mid = (left + right) // 2
        left_list = self._merge_range(lists, left, mid)
        right_list = self._merge_range(lists, mid + 1, right)

        return self._merge_two_lists(left_list, right_list)

    def _merge_two_lists(self, l1: ListNode, l2: ListNode) -> ListNode:
        dummy = ListNode(0)
        tail = dummy

        while l1 and l2:
            if l1.val <= l2.val:
                tail.next = l1
                l1 = l1.next
            else:
                tail.next = l2
                l2 = l2.next
            tail = tail.next

        tail.next = l1 if l1 else l2
        return dummy.next

# 辅助函数：构建测试用例
def build_list(vals):
    if not vals:
        return None
    head = ListNode(vals[0])
    curr = head
    for v in vals[1:]:
        curr.next = ListNode(v)
        curr = curr.next
    return head

def print_list(head):
    res = []
    while head:
        res.append(head.val)
        head = head.next
    return res

# 测试
sol = Solution()
lists = [build_list([1,4,5]), build_list([1,3,4]), build_list([2,6])]
result = sol.mergeKLists(lists)
print(print_list(result))  # [1, 1, 2, 3, 4, 4, 5, 6]
